package org.example.hot100_v2.medium;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * 找到 s 中所有 p 的 异位词 的子串，返回这些子串的起始索引
 * @author kylin
 * @date 2026/6/30
 */

public class _438 {

    public static List<Integer> findAnagrams(String s, String p) {
        Map<Character, Integer> pMap = new HashMap<>();
        for (char c : p.toCharArray()) {
            pMap.put(c, pMap.getOrDefault(c, 0) + 1);
        }

        List<Integer> ans = new ArrayList<>();

        Map<Character, Integer> sMap = new HashMap<>();

        int ptr = 0, i = 0;
        while (ptr < s.length()) {
            char c = s.charAt(ptr);
            sMap.put(c, sMap.getOrDefault(c, 0) + 1);
            if (!pMap.containsKey(c)) {
                ptr++;
                i = ptr;
                sMap.clear();
            } else {
                if (sMap.get(c) <= pMap.getOrDefault(c, 0)) {
                    if (ptr - i + 1 >= p.length()) {
                        ans.add(i);
                        ptr++;

                        // 如果头尾相同，则继续往下走
                        while (ptr < s.length() && s.charAt(ptr) == s.charAt(i)) {
                            i++;
                            ans.add(i);
                            ptr++;
                        }
                        i += 1;
                        ptr = i;
                        sMap.clear();
                    } else {
                        ptr++;
                    }
                } else { // 不满足
                    i += 1;
                    ptr = i;
                    sMap.clear();
                }
            }

        }

        return ans;
    }

    public static void main(String[] args) {
        System.out.println(findAnagrams("abacbabc", "abc")); // [1,2,3,5]
        System.out.println(findAnagrams("abaacbabc", "abc"));;
        System.out.println(findAnagrams("cbaebabacd", "abc"));;
        System.out.println(findAnagrams("abab", "ab"));;
        System.out.println(findAnagrams("", ""));;
    }
}
